head.script:
//물류/공통(통합)/기준작업경로/기준작업경로관리

scwin.MSG_LO_INF_002 = "사업부문을 선택하여 주십시오.";
scwin.MSG_LO_INF_003 = "사업영역은 반드시 한 개 이상 체크되어야 합니다.";
scwin.MSG_LO_ERR_001 = "하나 이상의 기준작업별 작업단계를 입력하십시오.";

scwin.MSG_LO_ERR_002 = "작업단계를 선택하십시오.";
scwin.MSG_LO_ERR_003 = "기준작업경로를 삭제를 먼저 취소하십시오.";

scwin.pos_rowSts = 0;
scwin.F_CANROWCHANGE = true;
scwin.searchFlag = false;
scwin.selpchItemNmBfVal = "";

scwin.onpageload = function() {

};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_OnLoad
// scwin.desc : 화면로딩시 
//-------------------------------------------------------------------------   
scwin.f_OnLoad = function () {	
	scwin.f_defaultValue();
};

scwin.onUdcCompleted = function() {
    const codeOptions = [
        { grpCd: "SD113", compID: "lc_cnd_OdrKndCd,lc_OdrKndCd"} //계약요율구분
        ,{ grpCd: "LO121", compID: "gr_workPathEachworkStep:wrkPlClsCd"} //작업장구분
    ]  
    $c.data.setCommonCode(codeOptions, scwin.f_commonCodeCallback);

    scwin.f_OnLoad();
};

scwin.f_commonCodeCallback = function(){
    dlt_commonCodeLO121.insertRow(0);
    dlt_commonCodeLO121.setCellData(0, "cd", " ");
    dlt_commonCodeLO121.setCellData(0, "cdNm", "→");
    dlt_commonCodeLO121.sort("cd",0);
    //ds_wrkPlClsCd.setJSON(dlt_commonCodeLO121.getAllJSON());
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_newCtrt
// scwin.desc : 신규화면 클릭
//-------------------------------------------------------------------------
scwin.f_newCtrt = function () {

};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_defaultValue
// scwin.desc : 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {

    ds_view_cond.set("bizDivCntrYn",1);
    ds_view_cond.set("bizDivBulkYn",1);
    ds_view_cond.set("bizDomTransYn",1);
    ds_view_cond.set("bizDomStvYn",1);
    ds_view_cond.set("bizDomStrYn",1);
    ds_view_cond.set("bizDomInatYn",1);
    ds_view_cond.set("bizDomTplYn",1);

	$c.gus.cfDisableKey();
	// $c.gus.cfDisableObjects([btn_save,udc_addRow2,btn_rowInsert]);
    $c.gus.cfDisableObjects([btn_save, btn_rowInsert, btn_stepAdd, btn_stepDel]);

	// 작업장구분 Lokkup DataSet Setting    
    ds_wrkPlClsCd.setJSON([]);

    $c.sbm.execute(sbm_srchLkStepNo); //기준작업경로별 작업단계 그리드 콤보
};

scwin.f_dsFilter = function(dsNm, rowPosition){
    // console.log("============scwin.f_dsFilter:"+dsNm+", rowPosition:"+rowPosition+", getRowPosition:"+ds_workPath.getRowPosition());
    if(dsNm == "ds_workPathEachworkStep"){
        var row = ds_workPathEachworkStep.getRowPosition();

        ds_workPathEachworkStep.clearFilter();
        let vStdWrkPathNo = ds_workPath.getCellData(ds_workPath.getRowPosition(), "stdWrkPathNo");
        // console.log("========vStdWrkPathNo:"+vStdWrkPathNo);
        // 값이 존재할 경우 해당 값으로, 없을 경우 검색되지 않을 임의의 값(___NONE___)으로 설정
        let filterValue = (vStdWrkPathNo && vStdWrkPathNo !== "") ? vStdWrkPathNo : "___NONE___";
        // setColumnFilter API를 사용한 필터링 적용
        ds_workPathEachworkStep.setColumnFilter({
            type: "row",              // 행 단위 필터링
            colIndex: "stdWrkPathNo",   // 필터링할 컬럼 ID 또는 인덱스
            key: filterValue,         // 필터링 기준 값
            condition: "and",           // 비교 연산자 (일치 여부 확인)
            exactMatch:true
        });

        //if (ds_workPathEachworkStep.getCellData(row,"stdWrkPathNo") == ds_workPath.getCellData(ds_workPath.getRowPosition(),"stdWrkPathNo")) return true;
		//else return false;
    }else if(dsNm == "ds_LkStepNo"){
        var row = ds_workPathEachworkStep.getRowPosition();
        var v_wrkPlClsCd = ds_workPathEachworkStep.getCellData(row, "wrkPlClsCd");
        var v_fltrCd1 = "";

        // 작업구분 코드로 FLTR_CD_1 값 조회	
        if(v_wrkPlClsCd != ""){
            for(i = 0 ; i < dlt_commonCodeLO121.getRowCount(); i++){
                if(v_wrkPlClsCd == dlt_commonCodeLO121.getCellData(i,"cd")){
                    v_fltrCd1 = dlt_commonCodeLO121.getCellData(i,"fltrCd1");
                }
            }
        }

        console.log("scwin.f_dsFilter ~~"+v_wrkPlClsCd+" :"+v_fltrCd1);
        if (ds_workPathEachworkStep.getRowCount() > 0) {
            if(v_fltrCd1 == "02"){	// 하역 (작업단계코드 : 01)
                //console.log("scwin.f_dsFilter 02 ~~");
                var filterOptions = {type:'row', colIndex:'topWrkStpCd', key:"01", condition:'and'};
                ds_LkStepNoLink.clearFilter();
                ds_LkStepNoLink.setColumnFilter(filterOptions);
            } else if(v_fltrCd1 != "02" && v_fltrCd1 != ""){	// 보관 (작업단계코드 : 03)
                //console.log("scwin.f_dsFilter 02 아님~ ~~");
                var filterOptions = {type:'row', colIndex:'topWrkStpCd', key:"03", condition:'and'};
                ds_LkStepNoLink.clearFilter();
                ds_LkStepNoLink.setColumnFilter(filterOptions);
            } else {	// 운송 (작업단계코드 : 02)
                //console.log("scwin.f_dsFilter 기타~ ~~");
                var filterOptions = {type:'row', colIndex:'topWrkStpCd', key:"02", condition:'and'};
                ds_LkStepNoLink.clearFilter();
                ds_LkStepNoLink.setColumnFilter(filterOptions);
            }

            ds_LkStepNoLink.sort("wrkStpCd",0);
        }
    }
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Addrow
// scwin.desc : 그리드 칼럼 추가
//-------------------------------------------------------------------------
scwin.f_Addrow1 = async function () {
    // console.log("f_Addrow1~"+scwin.F_CANROWCHANGE);
  /*  if (scwin.F_CANROWCHANGE == false) {
        return;
    }
    */

    var bizDivCntrYn = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "bizDivCntrYn" );
    var bizDivBulkYn = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "bizDivBulkYn" );
    var bizDomTplYn = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "bizDomTplYn" );
    var bizDomTransYn = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "bizDomTransYn" );
    var bizDomStvYn = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "bizDomStvYn" );
    var bizDomStrYn = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "bizDomStrYn" );
    var bizDomInatYn = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "bizDomInatYn" );
    var stdWrkPathNm = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "stdWrkPathNm" );
    var rmk = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "rmk" );
    var odrKndCd = ds_workPath.getCellData(ds_workPath.getRowPosition(),  "odrKndCd" );


    var row = ds_workPath.insertRow(ds_workPath.getRowCount());   
    if (scwin.F_CANROWCHANGE == true) {
        // console.log("=============ds_workPath.getInsertedJSON().length:"+ds_workPath.getInsertedJSON().length);
        /* if(ds_workPath.getInsertedJSON().length > 0){
            return;
        } */
        // console.log("f_Addrow row~"+row);
        // console.log("f_Addrow1 row~"+row);

        ds_workPath.setCellData(row,  "stdWrkPathNo", row+1);
        ds_workPath.setCellData(row,  "bizDivCntrYn", bizDivCntrYn);
        ds_workPath.setCellData(row, "bizDivBulkYn", bizDivBulkYn);
        ds_workPath.setCellData(row,  "bizDomTplYn", bizDomTplYn);
        ds_workPath.setCellData(row,  "bizDomTransYn", bizDomTransYn);	 
        ds_workPath.setCellData(row,  "bizDomStvYn", bizDomStvYn);
        ds_workPath.setCellData(row,  "bizDomStrYn", bizDomStrYn);
        ds_workPath.setCellData(row,  "bizDomInatYn", bizDomInatYn);
        ds_workPath.setCellData(row,  "stdWrkPathNm", "");
        ds_workPath.setCellData(row,  "rmk", "");
        ds_workPath.setCellData(row,  "odrKndCd", odrKndCd);
        ds_workPath.setCellData(row,  "useYn", 1);       
        ds_workPath.setCellData(row, "estTrgtYn", 0);

        // scwin.f_dsFilter("ds_workPathEachworkStep", row); 
    }

    ds_workPath.setRowPosition(row);
    gr_workPath.setFocusedCell(row, "stdWrkPathNm", false);
 	$c.gus.cfEnableKeyData();
 	// $c.gus.cfEnableObjects([btn_save,udc_addRow2,btn_rowInsert]);
    $c.gus.cfEnableObjects([btn_save, btn_rowInsert, btn_stepAdd, btn_stepDel]);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Addrow
// scwin.desc : 그리드 칼럼 추가
//-------------------------------------------------------------------------
scwin.f_Addrow2 = async function () {

    if (ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "D" ) {
        await $c.gus.cfAlertMsg(scwin.MSG_LO_ERR_003);	//기준작업경로를 먼저 취소하십시오.
        return;
    }    

    for(var i=0; i< ds_workPathEachworkStep.getRowCount(); i++) {
        if (ds_workPathEachworkStep.getCellData(i,"stdWrkPathNo") == ds_workPath.getCellData(ds_workPath.getRowPosition(),"stdWrkPathNo")) {
            // ds_workPathEachworkStep.modifyRowStatus(i, "C");
        }
    }

    var row = ds_workPathEachworkStep.insertRow();
    ds_workPathEachworkStep.setCellData(row, "stdWrkPathNo", ds_workPath.getCellData(ds_workPath.getRowPosition(), "stdWrkPathNo" ));
    ds_workPathEachworkStep.setCellData(row, "wrkStpSeq", (ds_workPathEachworkStep.getRowCount() * 10)+"");
    gr_workPathEachworkStep.setFocusedCell(row, "wrkPlClsCd", false);

    $c.gus.cfEnableKeyData();
 	// $c.gus.cfEnableObjects([btn_save,udc_addRow2,btn_rowInsert]);
    $c.gus.cfEnableObjects([btn_save, btn_rowInsert, btn_stepAdd, btn_stepDel]);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_insertRow
// scwin.desc : 행삽입 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_insertRow = async function (){

	var seq = 1;
	if (ds_workPath.getRowCount() == 0) {
		await $c.gus.cfAlertMsg(MSG_SD_ERR_001);
		return;
	}

	if (ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "D" ) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_003);	//기준작업경로를 먼저 취소하십시오.
		return;
	}

    var insertRow = $c.gus.cfIsNull(ds_workPathEachworkStep.getRowPosition()) ? 0 : ds_workPathEachworkStep.getRowPosition()+1;
    var row = ds_workPathEachworkStep.insertRow(insertRow);

    ds_workPathEachworkStep.setCellData(row, "stdWrkPathNo", ds_workPath.getCellData(ds_workPath.getRowPosition(), "stdWrkPathNo" ));
    for(var i = 0; i < ds_workPathEachworkStep.getRowCount(); i++){
		if (ds_workPathEachworkStep.getRowStatus(i) != "D") {
			ds_workPathEachworkStep.setCellData(i,"wrkStpSeq", (seq * 10)+"");
            //console.log("insert 시 : "+seq * 10);
			seq++;
		}
	}

    gr_workPathEachworkStep.setFocusedCell(insertRow, "wrkPlClsCd", false);
/*
	if (ds_workPathEachworkStep.getRowCount() == 0) {
		ds_workPathEachworkStep.setCellData(row, "stdWrkPathNo", ds_workPath.getCellData(ds_workPath.getRowPosition(), "stdWrkPathNo" ));
		ds_workPathEachworkStep.setCellData(row, "wrkStpSEq", row * 10);
	} else {
		ds_workPathEachworkStep.setCellData(row, "stdWrkPathNo", ds_workPath.getCellData(ds_workPath.getRowPosition(), "stdWrkPathNo" ));
		ds_workPathEachworkStep.setCellData(row, 'ctrtWrkStpSeq', ds_workPathEachworkStep.getCellData(row - 1, 'wrkStpSEq') + 10);
	}

	//for ( i = 1 ;i <= ds_workPathEachworkStep.getRowCount(); i++) {
    for(var i = 0; i < ds_workPathEachworkStep.getRowCount(); i++){
		//if (ds_workPathEachworkStep.getRowStatus(i) != 2) {
		if (ds_workPathEachworkStep.getRowStatus(i) != "D") {
			ds_workPathEachworkStep.setCellData(i,"wrkStpSEq", seq * 10);
			seq++;
		}
	}
*/
};


//-------------------------------------------------------------------------
// scwin.name : scwin.f_Delrow
// scwin.desc : 메인 그리드를 삭제했을 경우 sub그리드의 데이타까지 삭제
//-------------------------------------------------------------------------
scwin.f_Delrow1 = function () {
    // console.log("f_Delrow1~"+ds_workPath.getRowPosition());

	var seq = 1;
    const rowPosition = ds_workPath.getRowPosition();
    // console.log("==========ds_workPath.getRowStatus(rowPosition):"+ds_workPath.getRowStatus(rowPosition));
    if (ds_workPath.getRowStatus(rowPosition) == "C") {
        scwin.f_Undo1();
        return;
    }

    scwin._deleteFalg = true;
    if(ds_workPath.getRowStatus(rowPosition) == "C") {
        ds_workPath.removeRow(rowPosition);
    }else{
        ds_workPath.deleteRow(rowPosition);
        gr_workPath.setFocusedCell(rowPosition, "stdWrkPathNo");
    }

    var strStdWrkPathNo = ds_workPath.getCellData(rowPosition, "stdWrkPathNo");

    var intRowcnt = ds_workPathEachworkStep.getRowCount();


    for( var i = 0; i < intRowcnt; i++){
        if ( strStdWrkPathNo == ds_workPathEachworkStep.getCellData(i, "stdWrkPathNo") ) {

            //if (ds_workPathEachworkStep.getRowStatus(ds_workPathEachworkStep.getRowCount()) == 0  || 
            //    ds_workPathEachworkStep.getRowStatus(ds_workPathEachworkStep.getRowCount()) == 3  ||
            //    ds_workPathEachworkStep.getRowStatus(ds_workPathEachworkStep.getRowCount()) == 2) {

            if (ds_workPathEachworkStep.getRowStatus(i) == "R"  || 
                ds_workPathEachworkStep.getRowStatus(i) == "U" ||
                ds_workPathEachworkStep.getRowStatus(i) == "D") {

                ds_workPathEachworkStep.deleteRow(i);
            } else {
                ds_workPathEachworkStep.undoRow(i);
            }
        }

    }
	scwin.f_dsFilter("ds_workPathEachworkStep", rowPosition);
	$c.gus.cfEnableKeyData();
    // $c.gus.cfEnableObjects([btn_save,udc_addRow2,btn_rowInsert]);
    $c.gus.cfEnableObjects([btn_save, btn_rowInsert, btn_stepAdd, btn_stepDel]);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Delrow
// scwin.desc : 메인 그리드를 삭제했을 경우 sub그리드의 데이타까지 삭제
//-------------------------------------------------------------------------
scwin.f_Delrow2 = function () {

	var seq = 1;
    var row = ds_workPathEachworkStep.getRowPosition();
    if(ds_workPathEachworkStep.getRowStatus(row) == "C") {
        ds_workPathEachworkStep.removeRow(row);
    } else {
        ds_workPathEachworkStep.deleteRow(row);
    }

    for( var i = 0; i < ds_workPathEachworkStep.getRowCount(); i++ ) {
        //if (ds_workPathEachworkStep.getRowStatus(i) != 2) {
        if (ds_workPathEachworkStep.getRowStatus(i) != "D") {
            ds_workPathEachworkStep.setCellData(i,"wrkStpSeq", seq * 10);
            seq++;
        }
    }
    gr_workPathEachworkStep.setFocusedCell(row, "wrkPlClsCd", false);

	$c.gus.cfEnableKeyData();
    // $c.gus.cfEnableObjects([btn_save,udc_addRow2,btn_rowInsert]);
    $c.gus.cfEnableObjects([btn_save, btn_rowInsert, btn_stepAdd, btn_stepDel]);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Undo
// scwin.desc : 메인 그리드를 취소했을 경우 sub그리드까지 취소
//-------------------------------------------------------------------------
scwin.f_Undo1 = function () {

	var strStdWrkPathNo = ds_workPath.getCellData(ds_workPath.getRowPosition(), "stdWrkPathNo");

	var seq = 1;
	var intRowcnt = ds_workPathEachworkStep.getRowCount();

    // console.log("=======ds_workPath.getRowPosition():"+ds_workPath.getRowPosition()+":"+ds_workPath.getRowStatus(ds_workPath.getRowPosition()))
    //if(ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == 1 || ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == 2) {
    if(ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "C" || ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "D") {

        for (var i = 0; i < intRowcnt; i++ ) {
            if ( strStdWrkPathNo == ds_workPathEachworkStep.getCellData(i, "stdWrkPathNo") ) {
                if( ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "D" ) {
                    ds_workPathEachworkStep.undoRow(i);
                }
                /* if( ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "C" ) {
                    ds_workPathEachworkStep.removeRow(i);
                } else {
                    ds_workPathEachworkStep.undoRow(i);
                } */
            }
        }
    } 

    // console.log("=======ds_workPath.getRowPosition():"+ds_workPath.getRowPosition()+":"+ds_workPath.getRowStatus(ds_workPath.getRowPosition()));
    // if( ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "C" && ds_workPath.getRowPosition() == 0 ) {
    // if( ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "C" ) {
    //     ds_workPath.removeRow(ds_workPath.getRowPosition());
    // } else {
    //     ds_workPath.undoRow(ds_workPath.getRowPosition());
    // }
    // console.log("============================[1]:"+ds_workPath.getRowStatus(ds_workPath.getRowPosition()) );
    if( ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "C" ) {        
        ds_workPath.modifyRowStatus(ds_workPath.getRowPosition(), "R");
        ds_workPath.removeRow(ds_workPath.getRowPosition());
    } else {
        ds_workPath.undoRow(ds_workPath.getRowPosition());
    }

    if(ds_workPath.getRowCount() == 0) {
        $c.gus.cfDisableKey();
        // $c.gus.cfDisableObjects([btn_save,udc_addRow2,btn_rowInsert]);
        $c.gus.cfEnableObjects([btn_save, btn_rowInsert, btn_stepAdd, btn_stepDel]);
    }
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Undo
// scwin.desc : 메인 그리드를 취소했을 경우 sub그리드까지 취소
//-------------------------------------------------------------------------
scwin.f_Undo2 = async function () {
	var seq = 1;

    //if (ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == 2 ) {
    if (ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "D" ) {
        await $c.gus.cfAlertMsg(scwin.MSG_LO_ERR_003);	//기준작업경로를 먼저 취소하십시오.
        return;
    }

    // ds_workPathEachworkStep.undoRow(ds_workPathEachworkStep.getRowPosition());
    var row = ds_workPathEachworkStep.getRowPosition();
    if(ds_workPathEachworkStep.getRowStatus(row) == "C") {
        ds_workPathEachworkStep.removeRow(row);
    } else if(ds_workPathEachworkStep.getRowStatus(row) == "D") {
        ds_workPathEachworkStep.undoRow(row);
        ds_workPathEachworkStep.modifyRowStatus(row, "U");
    }

    for (var i = 0 ;i < ds_workPathEachworkStep.getRowCount(); i++) {
        //if (ds_workPathEachworkStep.getRowStatus(i) != 2) {
        if (ds_workPathEachworkStep.getRowStatus(i) != "D") {
            ds_workPathEachworkStep.setCellData(i,"wrkStpSeq", seq * 10);
            seq++;
        }

    }
    gr_workPathEachworkStep.setFocusedCell(row, "wrkPlClsCd", false);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Retrieve
// scwin.desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (strwrkStpCd) {     

    if (! await scwin.f_reqFieldCheck()){
    	return;
    }

    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_reqFieldCheck
// scwin.desc : 조회조건 검색
//-------------------------------------------------------------------------
scwin.f_reqFieldCheck = async function () {   

    //계약영역 입력 체크
  	if (cbx_cnd_bizDivCntrYn.getValue() == 0 && 
  		cbx_cnd_bizDivBulkYn.getValue() == 0 ) {

		await $c.gus.cfAlertMsg(scwin.MSG_LO_INF_002);
		return false;
	}

	//계약부문 입력 체크
	if (cbx_cnd_bizDomTransYn.getValue() == 0 && 
		cbx_cnd_bizDomStvYn.getValue() == 0 && 
		cbx_cnd_bizDomStrYn.getValue() == 0 &&
  		cbx_cnd_bizDomInatYn.getValue() == 0 && 
  		cbx_cnd_bizDomTplYn.getValue() == 0) {

		await $c.gus.cfAlertMsg(scwin.MSG_LO_INF_003);
		return false;
	}
	return true;
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Save
// scwin.desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {

	var i = 1;
	var cnt = 0;
	scwin.pos_rowSts = ds_workPath.getRowPosition();
    // console.log("==============[f_Save] scwin.pos_rowSts:"+scwin.pos_rowSts+":"+ds_workPath.getRowStatus(ds_workPath.getRowPosition()));

	//if(ds_workPath.isUpdated==false && ds_workPathEachworkStep.isUpdated==false){

	if( ds_workPath.getRowStatus(ds_workPath.getRowPosition()) == "R" && ds_workPath.getModifiedJSON().length == 0 && ds_workPathEachworkStep.getModifiedJSON().length == 0){
