//-------------------------------------------------------------------------
// scwin.name : scwin.f_ReqFieldChk
// scwin.desc : 필수 항목 체크
//-------------------------------------------------------------------------
scwin.f_ReqFieldChk = async function () {

	if (rd_useYn.getValue() == "") {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_002,["사용여부"]);
        scwin.F_CANROWCHANGE = false;
		return false;
	}

	//사업부문 입력 체크
  	if (cbx_bizDivCntrYn.getValue() == 0 && cbx_bizDivBulkYn.getValue() == 0 ) {
		await $c.gus.cfAlertMsg(scwin.MSG_LO_INF_002);	// 사업부문을 선택하여 주십시오.
        scwin.F_CANROWCHANGE = false;
		return false;
	}

	//사업영역 입력 체크
	if (cbx_bizDomStvYn.getValue() == 0 && cbx_bizDomTransYn.getValue() == 0 && cbx_bizDomStrYn.getValue() == 0 && cbx_bizDomInatYn.getValue() == 0 && cbx_bizDomTplYn.getValue() == 0 ) {
		await $c.gus.cfAlertMsg(scwin.MSG_LO_INF_003);	// 사업영역은 반드시 한 개 이상 체크되어야 합니다.
        scwin.F_CANROWCHANGE = false;
		return false;
	}

	if($c.gus.cfIsNull(ed_StdWrkPathNm.getValue())){
        await $c.win.alert("기준작업경로명은(는) 필수 입력 항목입니다.");
        scwin.F_CANROWCHANGE = false;
		return false;
    }

 	//필수입력항목 체크
	if (await $c.gus.cfValidate([oRecevInfo, gr_workPath, gr_workPathEachworkStep],null,true)== false) {
        scwin.F_CANROWCHANGE = false;
  		return false;
	}

    // console.log("scwin.f_ReqFieldChk getRowPosition~~"+ds_workPath.getRowPosition());
    // console.log("scwin.f_ReqFieldChk getRowStatus~~"+ds_workPath.getRowStatus(ds_workPath.getRowPosition()));
	//if (ds_workPath.getRowStatus(ds_workPath.getRowPosition()) != 2 && ds_workPathEachworkStep.RealCount(1,ds_workPathEachworkStep.getRowCount()) == 0){
    let vStepCnt = 0;
    for (var i=0; i < ds_workPathEachworkStep.getAllFilteredJSON().length; i++) {
        // console.log("===i["+i+"]"+ds_workPathEachworkStep.getRowStatus(i));
        if( ds_workPathEachworkStep.getRowStatus(i) == "D" ) {
            vStepCnt++;
        }
    }
    // console.log("=========vStepCnt:"+vStepCnt+", length:"+ds_workPathEachworkStep.getAllFilteredJSON().length+", getRowStatus:"+ds_workPath.getRowStatus(ds_workPath.getRowPosition()));
    if( ds_workPathEachworkStep.getAllFilteredJSON().length == vStepCnt && ds_workPath.getRowStatus(ds_workPath.getRowPosition()) != "D" ) {
        scwin.F_CANROWCHANGE = false;
		await $c.gus.cfAlertMsg(scwin.MSG_LO_ERR_001);	// 하나 이상의 기준작업별 작업단계를 입력하십시오.
        return false;
    }

    if ( ds_workPathEachworkStep.getAllFilteredJSON().length == 0 
            && ds_workPath.getRowStatus(ds_workPath.getRowPosition()) != "D")
    {
		scwin.F_CANROWCHANGE = false;
		await $c.gus.cfAlertMsg(scwin.MSG_LO_ERR_001);	// 하나 이상의 기준작업별 작업단계를 입력하십시오.
        gr_workPathEachworkStep.setFocusedCell(0, "wrkPlClsCd", false);
		return false;		
	}

    scwin.F_CANROWCHANGE = true;
	return true;
};

