scwin.sbm_retrieve_submitdone = async function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; 
        if( e.responseJSON.resultDataSet[0].Code == 0 ) {
            var rowcnt = ds_workPath.getRowCount();
            tbx_totalRows.setValue(rowcnt);

            if (ds_workPath.getRowCount() == 0) {
                scwin.f_dsFilter("ds_workPathEachworkStep"); 
                tbx_totalRows2.setValue("0");
                await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
                return;
            }
            rowcnt = ds_workPathEachworkStep.getRowCount();
            tbx_totalRows2.setValue(rowcnt);            

            $c.gus.cfEnableKeyData();
            // $c.gus.cfEnableObjects([btn_save,udc_addRow2,btn_rowInsert]);
            $c.gus.cfEnableObjects([btn_save, btn_rowInsert, btn_stepAdd, btn_stepDel]);

            //gr_workPathEachworkStep.DataID = "ds_workPathEachworkStep";
            // console.log("==============scwin.pos_rowSts:"+scwin.pos_rowSts);
            ds_workPath.sort("stdWrkPathNo",0);
            gr_workPath.setFocusedCell(scwin.pos_rowSts, "stdWrkPathNo", false);

            if(ds_workPathEachworkStep.getRowCount() > 0){
                gr_workPathEachworkStep.setFocusedCell(0, "wrkPlClsCd", false);
            }

            if($c.gus.cfCheckCreateFlag() == true) {
                $c.gus.cfTurnCreateFlag(false);
            }
            scwin.searchFlag = false;
        }
    } catch (e) {
       console.log("sbm_retrieve_submitdone : " + e);
    }
};

scwin.sbm_save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다.
        scwin.searchFlag = true; 
        scwin.f_Retrieve();
    }
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.searchFlag = true;
    scwin.f_Retrieve();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

