//-------------------------------------------------------------------------
// Grid 셀 편집모드 종료시 발생 이벤트
//-------------------------------------------------------------------------
scwin.gr_workPathEachworkStep_onafteredit = async function (rowIndex, columnIndex, value) {
    let row = rowIndex;
    let colid = gr_workPathEachworkStep.getColumnID(columnIndex);
    switch (colid) {

		case "selpchItemNm":
			if ( ds_workPathEachworkStep.getCellData(row,"selpchItemNm") == "" ) {
				ds_workPathEachworkStep.setCellData(row,"selpchItemCd","");	//매출항목코드
				return;
			}
			if( scwin.selpchItemNmBfVal == ds_workPathEachworkStep.getCellData(row,"selpchItemNm") ) {
				return;
			} else {

				if (ds_workPathEachworkStep.getCellData(row,"wrkStpCd") == "") {
					ds_workPathEachworkStep.setCellData(row,"selpchItemNm","");
					await $c.gus.cfAlertMsg(scwin.MSG_LO_ERR_002);
                    gr_workPathEachworkStep.setFocusedCell(row, "wrkStpCd", false);
					return;
				}

				ds_workPathEachworkStep.setCellData(row,"selpchItemCd","");	//매출항목코드

				var rtnList = new Array();

                udc_comCodeGrid.setSelectId('retrieveCtrtSelpchItemInfo');	
                udc_comCodeGrid.cfCommonPopUpAsync(
                            function(ret) { scwin.udc_comCodeGrid_callback(ret, row) } ,
										ds_workPathEachworkStep.getCellData(row,"selpchItemCd").trim(),	
										ds_workPathEachworkStep.getCellData(row,"selpchItemNm").trim(),	
										"T",		
							            '7',		
										null,	
										'150,170',	
										null,		
										'1,0,1,1',     
										'440',	
										'500',	
										null,		
										null,
										null,
										"F",
							            "매출항목,매출항목코드,매출항목명"
										);						
			}
			break;

        case "wrkPlClsCd" :

            ds_workPathEachworkStep.setCellData(row, "wrkStpCd", " ");        
            break;    

		default:
			break;
	}
};

