scwin.errIdx = 0;
scwin.ds_workPath_onrowpositionchange = async function (info) {
    // console.log("scwin.ds_workPath_onrowpositionchange-oldRowIndex:"+info.oldRowIndex+", newRowIndex:"+info.newRowIndex+":"+scwin.F_CANROWCHANGE);
    // console.log(info);

    if($c.util.isEmpty(info.newRowIndex)) return;

    scwin.f_dsFilter("ds_workPathEachworkStep");    
    var rowcnt = ds_workPathEachworkStep.getRowCount();
    tbx_totalRows2.setValue(rowcnt);

    gr_workPathEachworkStep.setFocusedCell(0, "wrkStpSeq", false);
};

scwin.ds_workPath_onbeforerowpositionchange = async function (info) { 
    if(scwin._deleteFalg) {
        scwin._deleteFalg = false;
        return;
    }
    if( $c.util.isEmpty(info.oldRowIndex) ) return;
    if( $c.util.isEmpty(info.newRowIndex) ) return;
    if( $c.util.isEmpty(ds_workPath.getRowStatus(ds_workPath.getRowPosition())) ) return;

    // console.log("======oldRowIndex:"+info.oldRowIndex+", oldRowStatus:"+ds_workPath.getRowStatus(info.oldRowIndex)+", newRowIndex:"+info.newRowIndex+", newRowStatus:"+ds_workPath.getRowStatus(info.newRowIndex));
    // console.log("============================[2]:"+ds_workPath.getRowStatus(ds_workPath.getRowPosition()) );
    //포지션 빠져나가면서 이전값 체크
    let valChk = await scwin.f_validCheck(info.oldRowIndex,true);
    if( !valChk ) {
        ds_workPath.setRowPosition(info.oldRowIndex, true); // Boolean:onrowpositionchange() 이벤트를 수행여부(false:수행, true:미수행)
        scwin.f_dsFilter("ds_workPathEachworkStep");
        tbx_totalRows2.setValue(ds_workPathEachworkStep.getModifiedJSON().length);
        return false;
    }
};

scwin.f_validCheck = async function(rowIndex,moveFlg){
    if(!scwin.searchFlag){ //데이터변경 중 일때
        if( ds_workPath.getRowStatus(rowIndex) != "R" ) {
            if(!$c.gus.cfIsNull(rowIndex) && ds_workPath.getCellData(rowIndex, "stdWrkPathNm") == ""){
                scwin.F_CANROWCHANGE = false;
                await $c.win.alert("기준작업경로명은(는) 필수 입력 항목입니다.");
                ds_workPath.setRowPosition(rowIndex, true);
                if(moveFlg) gr_workPath.setFocusedCell(rowIndex, "stdWrkPathNo", false);
                return false;
            }

            if(!$c.gus.cfIsNull(rowIndex) && ds_workPath.getCellData(rowIndex, "odrKndCd") == ""){
                scwin.F_CANROWCHANGE = false;
                await $c.win.alert("오더종류은(는) 필수 입력 항목입니다.");
                ds_workPath.setRowPosition(rowIndex, true);
                if(moveFlg) gr_workPath.setFocusedCell(rowIndex,"stdWrkPathNo",false);
                return false;
            }

            if (ds_workPathEachworkStep.getRowCount() == 0 ) {
                scwin.F_CANROWCHANGE = false;
                await $c.gus.cfAlertMsg(scwin.MSG_LO_ERR_001);
                ds_workPath.setRowPosition(rowIndex, true);
                if(moveFlg) gr_workPath.setFocusedCell(rowIndex,"stdWrkPathNo",false);
                return false;
            }

            for(var i=0;i<ds_workPathEachworkStep.getRowCount();i++){
                if($c.gus.cfIsNull(ds_workPathEachworkStep.getCellData(i, "wrkStpCd"))){
                    scwin.F_CANROWCHANGE = false;
                    await $c.win.alert("기준작업경로별 작업단계의 "+(i+1)+"번째 데이터에서 작업단계은(는) 필수 입력 항목입니다.");
                    return false;
                }

                if($c.gus.cfIsNull(ds_workPathEachworkStep.getCellData(i, "selpchItemNm"))){
                    scwin.F_CANROWCHANGE = false;
                    await $c.win.alert("기준작업경료별 작업단계의 "+(i+1)+"번째 데이터에서 매출입항목은(는) 필수 입력 항목입니다.");
                    return false;
                }
            }
        }
    }
    scwin.F_CANROWCHANGE = true;
    return true;
}

scwin.ds_workPathEachworkStep_onrowpositionchange = function (info) {
    var row = info.newRowIndex;
	$c.gus.cfPrepareHidVal(ds_workPathEachworkStep, row, ["selpchItemCd", "selpchItemNm"]);
};

scwin.ds_workPathEachworkStep_oncelldatachange = function (info) {
    var row = info.rowIndex;
    var colid = info.colID;

    /* if ( colid == "wrkPlClsCd" ) {
        ds_workPathEachworkStep.setCellData(row,"wrkStpCd","");
        scwin.f_dsFilter("ds_LkStepNo"); 
    } */		

    if (ds_workPathEachworkStep.getModifiedJSON().length > 0) {

        let vStsCnt = 0;
        for( var i=0; i < ds_workPathEachworkStep.getTotalRow(); i++ ) {
            let fIdx = ds_workPathEachworkStep.getFilteredRowIndex(i);
            if( fIdx >= 0 ) {
                if( ds_workPathEachworkStep.getRowStatus(fIdx) == "C" || ds_workPathEachworkStep.getRowStatus(fIdx) == "U" ) {
                    vStsCnt++;
                }
                // console.log("============fIdx["+fIdx+"] getRowStatus:"+ds_workPathEachworkStep.getRowStatus(fIdx)+", vStsCnt:"+vStsCnt);

            }
        }   

        for(var i=0; i< ds_workPathEachworkStep.getRowCount(); i++) {
            if (ds_workPathEachworkStep.getCellData(i,"stdWrkPathNo") == ds_workPathEachworkStep.getCellData(row,"stdWrkPathNo")){
                if( vStsCnt > 0 && ds_workPathEachworkStep.getRowStatus(i) == "R" ) {
                    ds_workPathEachworkStep.modifyRowStatus(i, "U");
                }
            }
        }       

        if (ds_workPath.getCellData(ds_workPath.getRowPosition(),"stdWrkPathNo") == ds_workPathEachworkStep.getCellData(row,"stdWrkPathNo")){
            ds_workPath.setCellData(ds_workPath.getRowPosition(),"chk","1");
        }
    }
};
